operations.schema:
input EditPhaseInput {
    phaseIndex: Int!
	actuals: GranteeActualsInput
	planned: GranteePlannedInput
	stats: GranteeStatsInput
	status: Status
}

input GranteeActualsInput {
	arbReceived: Float
	arbUtilized: Float
	arbRemaining: Float
	contractsIncentivized: [ContractInput]
	incentives: String
	summary: String
	disclosures: String
}

input GranteePlannedInput {
	arbToBeDistributed: Float
	contractsIncentivized: [ContractInput]
	distributionMechanism: [DistributionMechanism]
	changes: String
	expectations: String
}

input GranteeStatsInput {
	avgDailyTVL: Float
	avgDailyTXNS: Float
	avgDailyUniqueUsers: Float
	kpis: [NamedKpiInput]
	changes: String
	lessons: String
}

input NamedKpiInput {
	name: String
	value: Float
}

input ContractInput {
	contractId: ID!
	contractLabel: String
	contractAddress: String
}

input AddMetaInput {
    protocolVersion: String!
    isAdmin: Boolean
    value: String
}

input UpdateMetaInput {
    index: Float
    protocolVersion: String!
    isAdmin: Boolean
    value: String
}
